import 'package:flutter/material.dart';
import 'widget.dart';

class FeedScreen extends StatelessWidget {
  final List<Map<String, dynamic>> posts = [
    {"user": "igor", "image": "data:image/jpeg;base64,", "caption": "Codando o dia todo! 🚀"},
    {"user": "maria", "image": "data:image/jpeg;base64,", "caption": "Café e código. ☕"},
    {"user": "joao", "image": "data:image/jpeg;base64,", "caption": "Final de semana top!"},
  ];

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        backgroundColor: Colors.white,
        elevation: 1,
        title: Text("BudgetGran", style: TextStyle(color: Colors.black, fontWeight: FontWeight.bold)),
        actions: [
          IconButton(
            icon: Icon(Icons.person_outline, color: Colors.black),
            onPressed: () => Navigator.pushNamed(context, '/perfil'),
          )
        ],
      ),
      body: ListView.builder(
        itemCount: posts.length,
        itemBuilder: (context, index) {
          return PostWidget(post: posts[index]);
        },
      ),
    );
  }
}